public String caseSort(String str) {
    char[] arr = str.toCharArray();
    int n = arr.length;

    // Separate uppercase and lowercase letters
    List upper = new ArrayList<>();
    List lower = new ArrayList<>();

    for (char c : arr) {
        if (Character.isUpperCase(c)) {
            upper.add(c);
        } else {
            lower.add(c);
        }
    }

    // Sort both lists
    Collections.sort(upper);
    Collections.sort(lower);

    // Reconstruct the string
    int upperIndex = 0, lowerIndex = 0;
    for (int i = 0; i < n; i++) {
        if (Character.isUpperCase(arr[i])) {
            arr[i] = upper.get(upperIndex++);
        } else {
            arr[i] = lower.get(lowerIndex++);
        }
    }

    return new String(arr);
}

