def case_sort(s: str) -> str:
    upper = sorted(c for c in s if c.isupper())
    lower = sorted(c for c in s if c.islower())

    result = list(s)
    u_idx = l_idx = 0
    for i, c in enumerate(s):
        if c.isupper():
            result[i] = upper[u_idx]
            u_idx += 1
        else:
            result[i] = lower[l_idx]
            l_idx += 1

    return "".join(result)
